Rules.InvariantScript:
If(
    IsBlank(ProductionStart.SetupTimestamp),
    "Complete setup first",
    If(
        IsBlank(varPinCode),
        "Awaiting supervisor scan...",
        "✓ " & LookUp(
            ForAll(
                Split(ProductionStart.StaffIds, ","),
                {code: First(Split(Value, "|")).Value,
                 name: Last(Split(Value, "|")).Value}
            ),
            code = varPinCode
        ).name
    )
)

Set(varPinCode, "");
Set(varMatchedStaff, Blank());
Set(varPinError, "");
Set(varPinInputText, "");
Set(varShowPinOverlay, true)

If(
    Len(txt_pin_overlay_ps.Text) = 10,
    Set(varMatchedStaff,
        LookUp(
            ForAll(Split(ProductionStart.StaffIds, ","),
                {code: First(Split(Value, "|")).Value,
                 name: Last(Split(Value, "|")).Value}
            ),
            code = txt_pin_overlay_ps.Text
        )
    );
If(
    !IsBlank(varMatchedStaff),
    Set(varPinCode, txt_pin_overlay_ps.Text);
    Set(varSupervisorName, varMatchedStaff.name);
    Set(varPinError, ""),
    If(Len(txt_pin_overlay_ps.Text) > 0,
        Set(varPinError, "⚠ Code not recognised"))
)
)

If(
          IsBlank(varPinCode),
          "",
          "✓ " & LookUp(
              ForAll(
                  Split(ProductionStart.StaffIds, ","),
                  {code: First(Split(Value, "|")).Value,
                   name: Last(Split(Value, "|")).Value}
              ),
              code = varPinCode
          ).name
      )
